import{_ as t,o as e,c as o,a2 as r}from"./chunks/framework.ZhLefgN8.js";const _=JSON.parse('{"title":"拆合股","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/corporate-actions/stock-split.md","filePath":"zh-CN/stock-trading/corporate-actions/stock-split.md"}'),i={name:"stock-trading/corporate-actions/stock-split.md"};function s(c,a,n,l,p,d){return e(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="拆合股" tabindex="-1">拆合股 <a class="header-anchor" href="#拆合股" aria-label="Permalink to &quot;拆合股&quot;">​</a></h1><p>拆股和合股定义、处理时间、不足一股处理方式。</p><h2 id="什么是拆股" tabindex="-1">什么是拆股 <a class="header-anchor" href="#什么是拆股" aria-label="Permalink to &quot;什么是拆股&quot;">​</a></h2><p>拆股，又称 Stock Split。当一只股票的价格较高，影响股票的交易量及投资人（尤其是散户）的购买欲望，股份公司会考虑将股票拆股。拆股后，股东权益不变，公司的总市值也不变，但持仓数量会增加，股价按比例下降。</p><p>举例：腾讯控股（00700）曾在 2014-05-15 由 1 股拆分为 5 股。持有 100 股，拆股后变为 500 股，市场价格从 120 港币降为 24 港币，总市值维持 12,000 港币不变。</p><h2 id="什么是合股" tabindex="-1">什么是合股 <a class="header-anchor" href="#什么是合股" aria-label="Permalink to &quot;什么是合股&quot;">​</a></h2><p>合股是拆股的相反过程，又称 Reverse Split。当股票价格较低时，为了提升公司形象，上市公司会将已发行的股票按比例进行合并，即由多股合并为 1 股。合股后，股价按照相应比例提高，股东权益不变，公司的总市值也不变，但持仓数量会减少。</p><h2 id="拆合股处理时间" tabindex="-1">拆合股处理时间 <a class="header-anchor" href="#拆合股处理时间" aria-label="Permalink to &quot;拆合股处理时间&quot;">​</a></h2><p>美股：根据交易所提供的拆合股生效时间（effective date），交易日盘前开盘前会完成整个拆合股过程，盘前交易会交易已经过拆合的股票。</p><p>港股：根据交易所提供的拆合股生效时间（effective date），收市后完成拆合股及临时交易代码的变更。下一个交易日开市时段可以交易已经过拆合的股票。</p><h2 id="不足一股的处理" tabindex="-1">不足一股的处理 <a class="header-anchor" href="#不足一股的处理" aria-label="Permalink to &quot;不足一股的处理&quot;">​</a></h2><p>若发生拆合股后持仓不足一股，则会在企业行动后换为等额现金返还到客户账户。</p>',12)])])}const f=t(i,[["render",s]]);export{_ as __pageData,f as default};
